import{_ as e,o as t,c as o,a2 as r}from"./chunks/framework.Cr-Z7ngm.js";const p=JSON.parse('{"title":"账户常见问题","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"account/account-faq.md","filePath":"zh-CN/account/account-faq.md"}'),l={name:"account/account-faq.md"};function i(c,a,n,s,u,d){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="账户常见问题" tabindex="-1">账户常见问题 <a class="header-anchor" href="#账户常见问题" aria-label="Permalink to &quot;账户常见问题&quot;">​</a></h1><p>二步验证、短信验证码接收、休眠账户定义及激活方法。</p><h2 id="什么是二步验证" tabindex="-1">什么是二步验证 <a class="header-anchor" href="#什么是二步验证" aria-label="Permalink to &quot;什么是二步验证&quot;">​</a></h2><p>当进行交易、查看账户信息等与资产相关的操作时，需要输入交易密码。二步验证功能启用后，在校验完交易密码后，App 会通过安全验证或手机验证码进一步确认身份。</p><p>建议启用二步验证功能以保护账户安全。</p><h2 id="收不到短信验证码怎么办" tabindex="-1">收不到短信验证码怎么办 <a class="header-anchor" href="#收不到短信验证码怎么办" aria-label="Permalink to &quot;收不到短信验证码怎么办&quot;">​</a></h2><p>常见原因包括：短信被手机拦截、网络异常、收件箱已满。详细排查步骤参见<a href="/troubleshooting/收不到短信验证码">收不到短信验证码</a>。</p><h2 id="什么是休眠账户" tabindex="-1">什么是休眠账户 <a class="header-anchor" href="#什么是休眠账户" aria-label="Permalink to &quot;什么是休眠账户&quot;">​</a></h2><p>休眠账户是指长期未发生交易活动的账户。需同时满足以下条件：</p><ul><li>账户近 3 年无任何主动操作记录（包括证券交易、新股申购、基金认购、资金存入/提取、股票存入/提取等）</li><li>账户资产净值低于等值 100 港币</li></ul><p>休眠账户将暂停交易、出金及股票转出功能。如需重新激活，请通过以下方式联系长桥客服办理：</p><ul><li>在线客服</li><li>客服热线</li><li>客服邮箱</li></ul>',12)])])}const _=e(l,[["render",i]]);export{p as __pageData,_ as default};
